func TestLogEvaluation(t *testing.T) {
	logrusLogger := logrus.New()
	auditLogger := NewPolicyAuditLoggerWithLogger(logrusLogger, logrus.InfoLevel)

	// Create a simple evaluation result
	result := &PolicyEvaluationResult{
		PolicyKey: "test-policy-key",
		Verdict:   "allow",
		Reason:    "matches ingress rule",
