// TestLogEvaluationThreadSafety tests that LogEvaluation is thread-safe.
func TestLogEvaluationThreadSafety(t *testing.T) {
	logrusLogger := logrus.New()
	auditLogger := NewPolicyAuditLoggerWithLogger(logrusLogger, logrus.DebugLevel)

	done := make(chan bool)

	result := &PolicyEvaluationResult{
		PolicyKey: "test-policy",
		Verdict:   "allow",
	}

	ctx := context.Background()

	// Launch multiple goroutines to test thread safety
	for i := 0; i < 10; i++ {
		go func(idx int) {
			key := "policy-" + string(rune(idx))
			auditLogger.LogEvaluation(ctx, key, nil, result)
